INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Es war einmal an einem völlig normalen Montag, als..."},"en":{"text":"It was a perfectly normal Monday when..."},"es":{"text":"Era un lunes completamente normal cuando..."},"fr":{"text":"Il était une fois, un lundi tout à fait normal, quand..."},"pl":{"text":"Pewnego zupełnie zwyczajnego poniedziałku stało się tak, że..."},"ar":{"text":"ذات يوم إثنين عادي تماماً..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Niemand hätte gedacht, dass ausgerechnet heute..."},"en":{"text":"Nobody would have thought that today of all days..."},"es":{"text":"Nadie habria pensado que precisamente hoy..."},"fr":{"text":"Personne n''aurait pensé qu''aujourd''hui justement..."},"pl":{"text":"Nikt by nie pomyślał, że akurat dzisiaj..."},"ar":{"text":"لم يكن أحد يتوقع أن اليوم بالذات..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als die Uhr Mitternacht schlug, passierte etwas Unerwartetes:"},"en":{"text":"When the clock struck midnight, something unexpected happened:"},"es":{"text":"Cuando el reloj marco la medianoche, paso algo inesperado:"},"fr":{"text":"Quand l''horloge sonna minuit, quelque chose d''inattendu se produisit :"},"pl":{"text":"Kiedy zegar wybił północ, wydarzyło się coś niespodziewanego:"},"ar":{"text":"عندما دقت الساعة منتصف الليل، حدث شيء غير متوقع:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"In einer kleinen Stadt am Rande der Welt lebte..."},"en":{"text":"In a small town at the edge of the world lived..."},"es":{"text":"En un pequeno pueblo al borde del mundo vivia..."},"fr":{"text":"Dans une petite ville au bout du monde vivait..."},"pl":{"text":"W małym miasteczku na krańcu świata mieszkał..."},"ar":{"text":"في بلدة صغيرة على حافة العالم كان يعيش..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Brief kam ohne Absender und enthielt nur einen Satz:"},"en":{"text":"The letter arrived without a return address and contained only one sentence:"},"es":{"text":"La carta llego sin remitente y contenia solo una frase:"},"fr":{"text":"La lettre arriva sans expéditeur et ne contenait qu''une phrase :"},"pl":{"text":"List przyszedł bez nadawcy i zawierał tylko jedno zdanie:"},"ar":{"text":"وصلت الرسالة بدون مُرسِل وتحتوي على جملة واحدة فقط:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Alles begann mit einem merkwuerdigen Geraeusch im Kuehlschrank."},"en":{"text":"It all started with a strange noise in the refrigerator."},"es":{"text":"Todo empezo con un sonido extrano en la nevera."},"fr":{"text":"Tout commença par un bruit étrange dans le réfrigérateur."},"pl":{"text":"Wszystko zaczęło się od dziwnego dźwięku z lodówki."},"ar":{"text":"بدأ كل شيء بصوت غريب من الثلاجة."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Es regnete Gummibärchen, und niemand wusste warum."},"en":{"text":"It was raining gummy bears, and nobody knew why."},"es":{"text":"Llovian ositos de goma, y nadie sabia por que."},"fr":{"text":"Il pleuvait des oursons en gélatine, et personne ne savait pourquoi."},"pl":{"text":"Padały żelki z nieba i nikt nie wiedział dlaczego."},"ar":{"text":"أمطرت السماء حلوى الدببة ولم يعرف أحد لماذا."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der neue Nachbar hatte ein Geheimnis, das alle ändern würde."},"en":{"text":"The new neighbor had a secret that would change everything."},"es":{"text":"El nuevo vecino tenia un secreto que lo cambiaria todo."},"fr":{"text":"Le nouveau voisin avait un secret qui allait tout changer."},"pl":{"text":"Nowy sąsiad miał tajemnicę, która miała wszystko zmienić."},"ar":{"text":"الجار الجديد كان لديه سر سيغير كل شيء."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Hund sah mich an und sagte plötzlich:"},"en":{"text":"My dog looked at me and suddenly said:"},"es":{"text":"Mi perro me miro y de repente dijo:"},"fr":{"text":"Mon chien me regarda et dit soudainement :"},"pl":{"text":"Mój pies spojrzał na mnie i nagle powiedział:"},"ar":{"text":"نظر إليّ كلبي وقال فجأة:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Auf dem Dachboden fand ich eine Kiste mit der Aufschrift \"NICHT OEFFNEN\"."},"en":{"text":"In the attic, I found a box labeled \"DO NOT OPEN\"."},"es":{"text":"En el desvan encontre una caja con la etiqueta \"NO ABRIR\"."},"fr":{"text":"Au grenier, je trouvai une boîte marquée « NE PAS OUVRIR »."},"pl":{"text":"Na strychu znalazłem pudełko z napisem „NIE OTWIERAĆ\"."},"ar":{"text":"في العلية وجدت صندوقاً مكتوباً عليه \"لا تفتح\"."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Einladung kam per Brieftaube und roch nach Zimt."},"en":{"text":"The invitation arrived by carrier pigeon and smelled of cinnamon."},"es":{"text":"La invitacion llego por paloma mensajera y olia a canela."},"fr":{"text":"L''invitation arriva par pigeon voyageur et sentait la cannelle."},"pl":{"text":"Zaproszenie przyszło pocztą gołębią i pachniało cynamonem."},"ar":{"text":"وصلت الدعوة عبر حمام زاجل وكانت تفوح منها رائحة القرفة."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als ich aufwachte, stand ein Pinguin neben meinem Bett."},"en":{"text":"When I woke up, a penguin was standing next to my bed."},"es":{"text":"Cuando me desperte, habia un pinguino al lado de mi cama."},"fr":{"text":"Quand je me suis réveillé, un pingouin se tenait à côté de mon lit."},"pl":{"text":"Kiedy się obudziłem, obok mojego łóżka stał pingwin."},"ar":{"text":"عندما استيقظت، كان بطريق يقف بجانب سريري."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Supermarkt hatte geschlossen, also mussten wir..."},"en":{"text":"The supermarket was closed, so we had to..."},"es":{"text":"El supermercado estaba cerrado, asi que tuvimos que..."},"fr":{"text":"Le supermarché était fermé, alors nous avons dû..."},"pl":{"text":"Supermarket był zamknięty, więc musieliśmy..."},"ar":{"text":"كان السوبرماركت مغلقاً، لذا كان علينا أن..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Drei Fremde trafen sich zufaellig im Aufzug und..."},"en":{"text":"Three strangers met by chance in an elevator and..."},"es":{"text":"Tres desconocidos se encontraron por casualidad en un ascensor y..."},"fr":{"text":"Trois inconnus se retrouvèrent par hasard dans l''ascenseur et..."},"pl":{"text":"Trzech nieznajomych spotkało się przypadkiem w windzie i..."},"ar":{"text":"التقى ثلاثة غرباء بالصدفة في المصعد و..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Das Handy klingelte. Auf dem Display stand: \"Du hast 24 Stunden.\""},"en":{"text":"The phone rang. The display read: \"You have 24 hours.\""},"es":{"text":"El telefono sono. En la pantalla decia: \"Tienes 24 horas.\""},"fr":{"text":"Le téléphone sonna. Sur l''écran s''afficha : « Tu as 24 heures. »"},"pl":{"text":"Telefon zadzwonił. Na wyświetlaczu pojawiło się: „Masz 24 godziny.\""},"ar":{"text":"رنّ الهاتف. على الشاشة ظهر: \"لديك 24 ساعة.\""}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Kaffee schmeckte heute anders, und plötzlich konnte ich..."},"en":{"text":"The coffee tasted different today, and suddenly I could..."},"es":{"text":"El cafe sabia diferente hoy, y de repente podia..."},"fr":{"text":"Le café avait un goût différent aujourd''hui, et soudain je pouvais..."},"pl":{"text":"Kawa smakowała dziś inaczej i nagle mogłem..."},"ar":{"text":"كان طعم القهوة مختلفاً اليوم، وفجأة أصبحت أستطيع..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als der letzte Gast die Party verliess, bemerkten wir..."},"en":{"text":"When the last guest left the party, we noticed..."},"es":{"text":"Cuando el ultimo invitado se fue de la fiesta, notamos..."},"fr":{"text":"Quand le dernier invité quitta la fête, nous remarquâmes..."},"pl":{"text":"Kiedy ostatni gość opuścił imprezę, zauważyliśmy..."},"ar":{"text":"عندما غادر آخر ضيف الحفلة، لاحظنا..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Das Navigationsgeraet sagte \"Sie haben Ihr Ziel erreicht\", aber alles was ich sah, war..."},"en":{"text":"The GPS said \"You have reached your destination,\" but all I could see was..."},"es":{"text":"El GPS dijo \"Ha llegado a su destino\", pero todo lo que vi fue..."},"fr":{"text":"Le GPS dit « Vous êtes arrivé à destination », mais tout ce que je voyais, c''était..."},"pl":{"text":"Nawigacja powiedziała „Dotarłeś do celu\", ale wszystko, co widziałem, to..."},"ar":{"text":"قال الملاح \"وصلت إلى وجهتك\"، لكن كل ما رأيته كان..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Im Wartezimmer beim Zahnarzt fand ich eine geheimnisvolle Nachricht:"},"en":{"text":"In the dentist''s waiting room, I found a mysterious message:"},"es":{"text":"En la sala de espera del dentista encontre un mensaje misterioso:"},"fr":{"text":"Dans la salle d''attente du dentiste, je trouvai un message mystérieux :"},"pl":{"text":"W poczekalni u dentysty znalazłem tajemniczą wiadomość:"},"ar":{"text":"في غرفة انتظار طبيب الأسنان وجدت رسالة غامضة:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Paketbote brachte etwas, das niemand bestellt hatte:"},"en":{"text":"The delivery driver brought something nobody had ordered:"},"es":{"text":"El repartidor trajo algo que nadie habia pedido:"},"fr":{"text":"Le livreur apporta quelque chose que personne n''avait commandé :"},"pl":{"text":"Kurier przyniósł coś, czego nikt nie zamawiał:"},"ar":{"text":"أحضر عامل التوصيل شيئاً لم يطلبه أحد:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mitten im Meeting fiel die Maske meines Chefs — im woertlichen Sinne."},"en":{"text":"In the middle of the meeting, my boss''s mask fell off — literally."},"es":{"text":"En medio de la reunion, la mascara de mi jefe se cayo — literalmente."},"fr":{"text":"En pleine réunion, le masque de mon chef tomba — au sens propre."},"pl":{"text":"W środku spotkania maska mojego szefa spadła — dosłownie."},"ar":{"text":"في منتصف الاجتماع، سقط قناع مديري — حرفياً."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Katze brachte etwas nach Hause, das definitiv nicht normal war."},"en":{"text":"The cat brought something home that was definitely not normal."},"es":{"text":"El gato trajo algo a casa que definitivamente no era normal."},"fr":{"text":"Le chat ramena quelque chose à la maison qui n''était définitivement pas normal."},"pl":{"text":"Kot przyniósł do domu coś, co zdecydowanie nie było normalne."},"ar":{"text":"القطة أحضرت شيئاً للمنزل لم يكن طبيعياً بالتأكيد."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als ich mein altes Schulheft aufschlug, fiel ein Zettel heraus mit..."},"en":{"text":"When I opened my old school notebook, a note fell out with..."},"es":{"text":"Cuando abri mi viejo cuaderno del colegio, cayo una nota con..."},"fr":{"text":"Quand j''ouvris mon vieux cahier d''école, un papier en tomba avec..."},"pl":{"text":"Kiedy otworzyłem stary zeszyt szkolny, wypadła kartka z..."},"ar":{"text":"عندما فتحت دفتري المدرسي القديم، سقطت ورقة مكتوب عليها..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Fahrstuhl blieb zwischen zwei Stockwerken stecken, und mein Mitfahrer sagte:"},"en":{"text":"The elevator got stuck between two floors, and my fellow passenger said:"},"es":{"text":"El ascensor se quedo atrapado entre dos pisos, y mi companero dijo:"},"fr":{"text":"L''ascenseur resta coincé entre deux étages, et mon co-passager dit :"},"pl":{"text":"Winda zatrzymała się między piętrami, a mój współpasażer powiedział:"},"ar":{"text":"توقف المصعد بين طابقين، وقال رفيقي في المصعد:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Um Punkt Mitternacht leuchtete mein Handy auf — eine Nachricht von mir selbst."},"en":{"text":"At exactly midnight, my phone lit up — a message from myself."},"es":{"text":"A medianoche exacta, mi telefono se ilumino — un mensaje de mi mismo."},"fr":{"text":"À minuit pile, mon téléphone s''alluma — un message de moi-même."},"pl":{"text":"Dokładnie o północy mój telefon się zaświecił — wiadomość od mnie samego."},"ar":{"text":"في تمام منتصف الليل أضاء هاتفي — رسالة من نفسي."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Kinder fanden im Garten eine Schatztruhe, die..."},"en":{"text":"The kids found a treasure chest in the garden that..."},"es":{"text":"Los ninos encontraron un cofre del tesoro en el jardin que..."},"fr":{"text":"Les enfants trouvèrent dans le jardin un coffre au trésor qui..."},"pl":{"text":"Dzieci znalazły w ogrodzie skrzynię ze skarbem, która..."},"ar":{"text":"وجد الأطفال في الحديقة صندوق كنز..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als das Wifi ausfiel, passierte etwas Unglaubliches:"},"en":{"text":"When the WiFi went out, something incredible happened:"},"es":{"text":"Cuando se fue el wifi, paso algo increible:"},"fr":{"text":"Quand le Wi-Fi tomba en panne, quelque chose d''incroyable se produisit :"},"pl":{"text":"Kiedy Wi-Fi padło, wydarzyło się coś niewiarygodnego:"},"ar":{"text":"عندما انقطع الواي فاي، حدث شيء لا يُصدق:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Taxifahrer drehte sich um und sagte: \"Ich bringe Sie nicht dahin.\""},"en":{"text":"The taxi driver turned around and said: \"I''m not taking you there.\""},"es":{"text":"El taxista se dio la vuelta y dijo: \"Ahi no le llevo.\""},"fr":{"text":"Le chauffeur de taxi se retourna et dit : « Je ne vous emmène pas là-bas. »"},"pl":{"text":"Taksówkarz odwrócił się i powiedział: „Nie zawiozę was tam.\""},"ar":{"text":"استدار سائق التاكسي وقال: \"لن آخذك إلى هناك.\""}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Auf dem Flohmarkt fand ich eine Lampe — und ja, es war ein Dschinn drin."},"en":{"text":"At the flea market, I found a lamp — and yes, there was a genie inside."},"es":{"text":"En el mercadillo encontre una lampara — y si, habia un genio dentro."},"fr":{"text":"Au marché aux puces, je trouvai une lampe — et oui, il y avait un génie dedans."},"pl":{"text":"Na pchlim targu znalazłem lampę — i tak, był w niej dżin."},"ar":{"text":"في سوق البرغوث وجدت مصباحاً — ونعم، كان بداخله جني."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Strom fiel aus, und im Dunkeln hoerten wir..."},"en":{"text":"The power went out, and in the darkness we heard..."},"es":{"text":"Se fue la luz, y en la oscuridad escuchamos..."},"fr":{"text":"Le courant coupa, et dans l''obscurité nous entendîmes..."},"pl":{"text":"Prąd się wyłączył i w ciemności usłyszeliśmy..."},"ar":{"text":"انقطع التيار الكهربائي، وفي الظلام سمعنا..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Spiegelbild bewegte sich plötzlich anders als ich."},"en":{"text":"My reflection in the mirror suddenly moved differently than I did."},"es":{"text":"Mi reflejo en el espejo de repente se movio de forma diferente a mi."},"fr":{"text":"Mon reflet dans le miroir bougea soudainement différemment de moi."},"pl":{"text":"Moje odbicie w lustrze nagle poruszyło się inaczej niż ja."},"ar":{"text":"تحرك انعكاسي في المرآة فجأة بشكل مختلف عني."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die letzte Seite des Buches fehlte, also schrieb ich selbst:"},"en":{"text":"The last page of the book was missing, so I wrote my own:"},"es":{"text":"Faltaba la ultima pagina del libro, asi que escribi la mia:"},"fr":{"text":"La dernière page du livre manquait, alors j''écrivis moi-même :"},"pl":{"text":"Ostatnia strona książki brakowała, więc sam napisałem:"},"ar":{"text":"كانت الصفحة الأخيرة من الكتاب مفقودة، فكتبت بنفسي:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Hund bellte die Wand an — und die Wand bellte zurück."},"en":{"text":"My dog barked at the wall — and the wall barked back."},"es":{"text":"Mi perro ladro a la pared — y la pared le ladro de vuelta."},"fr":{"text":"Mon chien aboya contre le mur — et le mur aboya en retour."},"pl":{"text":"Mój pies szczekał na ścianę — a ściana szczekała z powrotem."},"ar":{"text":"نبح كلبي على الحائط — والحائط نبح رداً."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Im Fundbüro lag ein Gegenstand, den es eigentlich nicht geben sollte."},"en":{"text":"At the lost and found office, there was an object that shouldn''t exist."},"es":{"text":"En la oficina de objetos perdidos habia un objeto que no deberia existir."},"fr":{"text":"Au bureau des objets trouvés, il y avait un objet qui ne devrait pas exister."},"pl":{"text":"W biurze rzeczy znalezionych leżał przedmiot, który nie powinien istnieć."},"ar":{"text":"في مكتب المفقودات كان هناك شيء لا ينبغي أن يكون موجوداً."}}', 'medium', 'general', true);
